export type WineCategory =
  | "viso"
  | "corpo"
  | "solari"
  | "capelli"
  | "benessere"
  | "hempilla"
  | "detergenti";

export type Badge = "Novità" | "Best Seller" | "In Offerta" | "Biologico";

export interface Ingredient { name: string; benefit: string | null; }

export interface Wine {
  id: string;
  slug: string;
  name: string;
  /** Brand: Cannabilla / MELABILLA / Hempilla (shown where the template shows the producer). */
  producer: string;
  category: WineCategory;
  subcategory?: string;
  /** Origine — repurposes the template's `region` field. */
  region?: string;
  denomination?: string;
  /** Principali attivi — repurposes `grapeVarieties` for facets/filters. */
  grapeVarieties?: string[];
  vintage?: number;
  alcohol?: number;
  /** Formato, es. "50 ml". */
  volume: string;
  price: number;
  originalPrice?: number;
  /** Primary image (first of `images`). */
  image: string;
  /** Full real photo gallery (local /public paths). */
  images: string[];
  alt: string;
  /** Descrizione — repurposes `tastingNotes`. */
  tastingNotes: string;
  /** Benefici chiave — repurposes `foodPairings`. */
  foodPairings: string[];
  /** Certificazioni — repurposes `awards`. */
  awards?: string[];
  howToUse?: string;
  certifications?: string[];
  inci?: string;
  ingredients?: Ingredient[];
  format?: string;
  packaging?: string;
  subtitleText?: string;
  inStock: boolean;
  featured?: boolean;
  badges?: Badge[];
}

export interface CategoryMeta {
  id: WineCategory;
  slug: WineCategory;
  label: string;
  labelEn: string;
  tagline: string;
  description: string;
  image: string;
}

